/* ========= RSA 解密 AES key ========= */

function rsaDecrypt(base64Cipher) {
  const privateKey = forge.pki.privateKeyFromPem(PRIVATE_KEY_PEM);
  const encryptedBytes = forge.util.decode64(base64Cipher);
  const decrypted = privateKey.decrypt(encryptedBytes, "RSAES-PKCS1-V1_5");
  return decrypted; // 明文 AES key
}

/* ========= AES-CTR 解密 ========= */
/**
 * cipherText: base64
 * key: string（rsa 解出来的）
 */
function aesCtrDecrypt(cipherText, key) {
  const raw = Buffer.from(cipherText, "base64");

  const counter = raw.slice(0, 16);
  const content = raw.slice(16);

  const cipher = CryptoJS.AES.decrypt(
    { ciphertext: CryptoJS.lib.WordArray.create(content) },
    CryptoJS.enc.Utf8.parse(key),
    {
      mode: CryptoJS.mode.CTR,
      iv: CryptoJS.lib.WordArray.create(counter),
      padding: CryptoJS.pad.NoPadding
    }
  );

  return cipher.toString(CryptoJS.enc.Utf8);
}

/* ========= 总解密函数 ========= */

function decryptData({ base64Key, cipherText }) {
  const aesKey = rsaDecrypt(base64Key);
  const plainText = aesCtrDecrypt(cipherText, aesKey);
  return {
    aesKey,
    plainText
  };
}

